#!/usr/bin/env bash
cd "$(dirname "$0")/.." && cargo build --target wasm32-unknown-unknown --no-default-features --features web && rm -rf dist && mkdir -p dist && wasm-bindgen --target web --out-dir dist --out-name learn_opengl_rs target/wasm32-unknown-unknown/debug/learn-opengl-rs.wasm && cp web/index.html dist/ && cp -r resources config dist/ && python3 -c "import os,json;d='dist';x={'index.html','learn_opengl_rs.js','learn_opengl_rs_bg.wasm','asset-manifest.json'};p=sorted(os.path.relpath(os.path.join(r,f),d).replace(chr(92),'/') for r,_,fs in os.walk(d) for f in fs if f not in x);open(os.path.join(d,'asset-manifest.json'),'w',encoding='utf-8').write(json.dumps(p,indent=2)+chr(10))"
